options.systemMessage:
你是一個任務管理助理，解析用戶的自然語言輸入，輸出 JSON 格式。
只輸出 JSON，不要 markdown 標記，不要任何解釋文字。
日期必須是真實的 YYYY-MM-DD 字串（例如 2026-05-24），根據「今天日期」自行推算明天、後天、下週等，禁止輸出任何程式碼或變數。

時區：Asia/Taipei
週曆規則：一週從週一（禮拜一）開始，週日（禮拜日）是一週的最後一天。例如今天是週日，「下禮拜一」指的是明天（下一個週一），而非下下個週一。

intent 類型：create_task, query_task, complete_task, delete_task, unknown

create_task 格式：
{"intent":"create_task","task_name":"任務名稱","category":"分類","deadline_date":"2026-05-24","deadline_time":"23:59","reminder_time":"2026-05-24 09:00","priority":"中","status":"未完成","note":"","confidence":0.95}

complete_task 格式：
{"intent":"complete_task","task_name":"任務名稱","confidence":0.95}

query_task 格式：
{"intent":"query_task","query_range":"today|this_week|all","status":"未完成","confidence":0.95}

delete_task 格式：
{"intent":"delete_task","task_name":"任務名稱","confidence":0.95}

confirm_pending 格式（用戶確認新增圖片辨識的任務，如「確認新增」「確認」「好」「是」「對」「ok」）：
{"intent":"confirm_pending","confidence":0.95}

cancel_pending 格式（用戶取消圖片辨識的任務，如「取消」「不要」「算了」「不用」）：
{"intent":"cancel_pending","confidence":0.95}

parameters.jsCode:
// ⚠️ 請在下方填入你的 Gemini API Key
const apiKey = 'YOUR_GEMINI_API_KEY';

// 讀取 LINE 下載的圖片
const binaryBuffer = await helpers.getBinaryDataBuffer(0, 'data');
const imageBase64 = binaryBuffer.toString('base64');
const mimeType = $input.first().binary?.data?.mimeType || 'image/jpeg';

const today = $('Code (解析 replyToken & userId)').first().json.today;
const userId = $('Code (解析 replyToken & userId)').first().json.userId;

// 呼叫 Gemini Vision API
const requestBody = {
  contents: [{
    parts: [
      { inline_data: { mime_type: mimeType, data: imageBase64 } },
      { text: `今天日期：${today}\n週曆規則：一週從週一開始，週日是最後一天。\n\n請從這張圖片擷取所有任務和截止日期（課表、作業單、白板等），以 JSON 陣列格式輸出。每個任務包含：task_name, deadline_date (YYYY-MM-DD), deadline_time (HH:MM，預設23:59), category (學業/工作/生活/未分類), priority (高/中/低，預設中), reminder_time (YYYY-MM-DD HH:MM，預設截止日09:00)。只輸出 JSON 陣列，不要 markdown，不要說明文字。若圖片中沒有任務資訊，輸出空陣列 []。` }
    ]
  }]
};

let response;
try {
  response = await helpers.httpRequest({
    method: 'POST',
    url: `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${apiKey}`,
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(requestBody),
    json: true
  });
} catch(e) {
  return [{ json: { isError: true, userId, lineBodyText: '❌ 圖片分析失敗：' + e.message } }];
}

// 解析回傳的任務列表
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '';
const cleaned = text.replace(/```json|```/g, '').trim();

let tasks;
try {
  tasks = JSON.parse(cleaned);
} catch(e) {
  return [{ json: { isError: true, userId, lineBodyText: '❌ 無法辨識圖片中的任務，請確認圖片清晰度並重試。' } }];
}

if (!Array.isArray(tasks) || tasks.length === 0) {
  return [{ json: { isError: true, userId, lineBodyText: '📷 圖片中找不到任何任務，請傳送課表或作業單的清晰照片。' } }];
}

const now = new Date(Date.now() + 8 * 60 * 60 * 1000);
const nowStr = now.toISOString().slice(0, 16).replace('T', ' ');

return tasks.map((t, i) => ({
  json: {
    isError: false,
    id: String(now.getTime() + i),
    task_name: t.task_name || '',
    category: t.category || '未分類',
    deadline_date: t.deadline_date || today,
    deadline_time: t.deadline_time || '23:59',
    reminder_time: t.reminder_time || (t.deadline_date || today) + ' 09:00',
    priority: t.priority || '中',
    status: '未完成',
    note: '',
    source_message: '[圖片辨識]',
    created_at: nowStr,
    updated_at: nowStr,
    userId,
    totalCount: tasks.length
  }
}));

const allTasks = $input.first().json.tasks || [];
const count = allTasks.length;
const userId = allTasks[0]?.userId || $('Code (解析 replyToken & userId)').first().json.userId;
const list = allTasks.map((t, i) => `${i+1}. ${t.task_name} (${t.deadline_date})`).join('\n');
const lineBodyText = `📷 找到 ${count} 筆任務：\n\n${list}\n\n回覆「確認新增」儲存，或「取消」放棄`;
return [{ json: { userId, lineBodyText } }];

const allRows = $input.all();
const userId = $('Code (解析 replyToken & userId)').first().json.userId;
const pending = allRows.filter(r => r.json.userId === userId && r.json.status === 'pending');
if (pending.length === 0) {
  return [{ json: { noPending: true, userId, lineBodyText: '📋 目前沒有待確認的圖片任務。' } }];
}
const now = new Date(Date.now() + 8 * 60 * 60 * 1000);
const nowStr = now.toISOString().slice(0, 16).replace('T', ' ');
return pending.sort((a,b) => b.json.row_number - a.json.row_number).map(r => ({
  json: {
    noPending: false,
    row_number: r.json.row_number,
    id: r.json.id,
    task_name: r.json.task_name,
    category: r.json.category,
    deadline_date: r.json.deadline_date,
    deadline_time: r.json.deadline_time,
    reminder_time: r.json.reminder_time,
    priority: r.json.priority,
    note: r.json.note || '',
    source_message: r.json.source_message || '[圖片辨識]',
    created_at: r.json.created_at,
    updated_at: nowStr,
    userId,
    totalCount: pending.length
  }
}));

const tasks = $('Code (confirm prepare)').all().filter(t => !t.json.noPending);
const count = tasks.length;
const userId = $('Code (解析 replyToken & userId)').first().json.userId;
const list = tasks.map((t,i) => `${i+1}. ${t.json.task_name} (${t.json.deadline_date})`).join('\n');
const lineBodyText = `✅ 已新增 ${count} 筆任務：\n\n${list}`;
return [{ json: { userId, lineBodyText } }];

const allRows = $input.all();
const userId = $('Code (解析 replyToken & userId)').first().json.userId;
const pending = allRows.filter(r => r.json.userId === userId && r.json.status === 'pending');
if (pending.length === 0) {
  return [{ json: { noPending: true, userId, lineBodyText: '📋 目前沒有待取消的圖片任務。' } }];
}
return pending.sort((a,b) => b.json.row_number - a.json.row_number).map(r => ({
  json: { noPending: false, row_number: r.json.row_number, task_name: r.json.task_name, userId }
}));

const body = $input.first().json.body;
const event = body.events[0];
const messageType = event.message.type;
const message = event.message.text || '';
const messageId = event.message.id;
const replyToken = event.replyToken;
const userId = event.source.userId;

const now = new Date();
const taipeiOffset = 8 * 60 * 60 * 1000;
const taipeiMs = now.getTime() + taipeiOffset;
const today = new Date(taipeiMs).toISOString().split('T')[0];

return [{ json: { message, messageType, messageId, replyToken, userId, today } }];

const output = $input.first().json.output;
const cleaned = output.replace(/```json|```/g, '').trim();
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  parsed = { intent: 'unknown' };
}
const src = $('Code (解析 replyToken & userId)').first().json;
const userId = src.userId;
const source_message = src.message;

const lineBodyTo = userId;
let lineBodyText = '';
if (parsed.intent === 'create_task') {
  lineBodyText = '✅ 已新增任務：' + (parsed.task_name || '') + '\n📅 截止日：' + (parsed.deadline_date || '') + ' ' + (parsed.deadline_time || '') + '\n📂 分類：' + (parsed.category || '') + '\n⏰ 提醒：' + (parsed.reminder_time || '');
} else if (parsed.intent === 'unknown') {
  lineBodyText = '🤔 我不確定你想做什麼，請重新輸入！\n\n例如：\n・5/30 要交報告\n・資料庫作業完成了\n・我這週有什麼事？';
}

return [{ json: { ...parsed, userId, source_message, lineBodyTo, lineBodyText } }];

const rows = $input.all();
const intent = $('Code (解析 AI 意圖 JSON)').first().json;
const queryRange = intent.query_range;
const userId = intent.userId;

const offset = 8 * 60 * 60 * 1000;
const now = new Date(Date.now() + offset);
const today = now.toISOString().split('T')[0];
// 週末 = 本週日（台灣週曆：週一開始，週日結束）
const dayOfWeek = now.getDay(); // 0=週日
const daysUntilSunday = dayOfWeek === 0 ? 0 : 7 - dayOfWeek;
const weekEnd = new Date(now.getTime() + daysUntilSunday * 86400000).toISOString().split('T')[0];

let filtered = rows.filter(r => r.json.status !== '已完成' && r.json.status !== '已取消');
if (queryRange === 'today') {
  filtered = filtered.filter(r => r.json.deadline_date === today);
} else if (queryRange === 'this_week') {
  filtered = filtered.filter(r => r.json.deadline_date >= today && r.json.deadline_date <= weekEnd);
}
filtered.sort((a, b) => (a.json.deadline_date + (a.json.deadline_time || '')).localeCompare(b.json.deadline_date + (b.json.deadline_time || '')));

let lineBodyText = '';
if (filtered.length === 0) {
  const rangeText = { today: '今天', this_week: '這週', all: '目前' }[queryRange] || '目前';
  lineBodyText = `🎉 ${rangeText}沒有任何待辦事項，好好休息吧！`;
} else {
  const lines = ['📋 查詢結果（' + filtered.length + ' 筆）', ''];
  filtered.forEach((r, i) => {
    const p = { '高': '🔴', '中': '🟡', '低': '🟢' }[r.json.priority] || '';
    lines.push((i+1) + '. ' + p + ' ' + r.json.task_name);
    lines.push('   📅 ' + r.json.deadline_date + ' ' + (r.json.deadline_time || '') + ' | 📂 ' + r.json.category + ' | ' + r.json.status);
    lines.push('');
  });
  lineBodyText = lines.join('\n');
}

const lineBodyTo = userId;
return [{ json: { lineBodyTo, lineBodyText, userId } }];

const rows = $input.all();
const taskName = $('Code (解析 AI 意圖 JSON)').first().json.task_name;
const userId = $('Code (解析 AI 意圖 JSON)').first().json.userId;

const normalize = s => (s || '').replace(/\s/g, '');
const matched = rows.find(r =>
  normalize(r.json.task_name).includes(normalize(taskName)) &&
  r.json.status !== '已完成' &&
  r.json.status !== '已取消'
);

if (!matched) {
  return [{ json: { found: false, userId, lineBodyTo: userId, lineBodyText: '❌ 找不到任務「' + taskName + '」，請確認任務名稱。' } }];
}

return [{ json: {
  found: true,
  rowNumber: matched.json['row_number'],
  task_name: matched.json.task_name,
  userId,
  lineBodyTo: userId,
  lineBodyText: '✅ 已完成：' + matched.json.task_name + ' 🎉'
}}];

const rows = $input.all();
const taskName = $('Code (解析 AI 意圖 JSON)').first().json.task_name;
const userId = $('Code (解析 AI 意圖 JSON)').first().json.userId;

const normalize = s => (s || '').replace(/\s/g, '');
const matched = rows.find(r =>
  normalize(r.json.task_name).includes(normalize(taskName)) &&
  r.json.status !== '已取消'
);

if (!matched) {
  return [{ json: { found: false, userId, lineBodyTo: userId, lineBodyText: '❌ 找不到任務「' + taskName + '」，請確認任務名稱。' } }];
}

return [{ json: {
  found: true,
  rowNumber: matched.json['row_number'],
  task_name: matched.json.task_name,
  userId,
  lineBodyTo: userId,
  lineBodyText: '🗑️ 已取消：' + matched.json.task_name
}}];
